css:
.loader {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      gap: 6px;
      min-width: 48px;
      min-height: 20px;
    }
    .loader i {
      display: block;
      width: 10px;
      height: 10px;
      border-radius: 50%;
      background: var(--loader-color);
      animation: dotPulse 0.85s ease-in-out infinite;
    }
    .loader i:nth-child(1) { animation-delay: 0.00s; }
.loader i:nth-child(2) { animation-delay: 0.12s; }
.loader i:nth-child(3) { animation-delay: 0.24s; }
    @keyframes dotPulse { 0%, 80%, 100% { transform: translateY(0) scale(.75); opacity: .45; } 40% { transform: translateY(-8px) scale(1); opacity: 1; } }
